from typing import List

class Solution:
    def findKthSmallest(self, coins: List[int], k: int) -> int:
        def count_less_equal(x: int) -> int:
            total = 0
            for coin in coins:
                total += x // coin
            return total

        left = 1
        right = max(coins) * k

        while left < right:
            mid = (left + right) // 2
            cnt = count_less_equal(mid)
            if cnt < k:
                left = mid + 1
            else:
                right = mid

        return left
